#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        uint64_t N; scanf("%" PRIu64, &N);
        if(N==2) printf("Bob\n"); else printf("Alice\n");
    }
    return 0;
}

